    "html": "<div class=\"bg-[#0a0a0a] text-white font-sans min-h-screen flex flex-col md:flex-row\">\n  <!-- Sidebar -->\n  <aside class=\"w-full md:w-64 border-b md:border-b-0 md:border-r border-neutral-800 p-8 flex flex-col justify-between shrink-0 bg-black sticky top-0 md:h-screen\">\n    <div class=\"space-y-12\">\n      <h1 class=\"text-2xl font-black tracking-widest uppercase text-white hover:scale-95 transition-transform cursor-pointer\">LENS.</h1>\n      <nav class=\"flex md:flex-col gap-6 text-xs font-bold uppercase tracking-widest text-neutral-400\">\n        <a href=\"#gallery\" class=\"text-white\">Gallery</a>\n        <a href=\"#about\" class=\"hover:text-white transition-colors\">Biography</a>\n        <a href=\"#rates\" class=\"hover:text-white transition-colors\">Rates</a>\n        <a href=\"#contact\" class=\"hover:text-white transition-colors\">Book Session</a>\n      </nav>\n    </div>\n    <div class=\"text-[10px] text-neutral-600 uppercase tracking-widest mt-8 md:mt-0\">&copy; 2026 Lens Studio</div>\n  </aside>\n\n  <!-- Gallery Main Area -->\n  <main class=\"flex-1 p-8 space-y-16 overflow-y-auto\">\n    <!-- Showcase Gallery -->\n    <div id=\"gallery\" class=\"space-y-6\">\n      <h2 class=\"text-xs uppercase font-bold text-neutral-400 tracking-widest border-b border-neutral-800 pb-4\">Selected Showcase</h2>\n      <div class=\"grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6\">\n        <img src=\"https://images.unsplash.com/photo-1534528741775-53994a69daeb?auto=format&fit=crop&q=80&w=600\" class=\"w-full object-cover rounded aspect-[3/4] hover:opacity-80 transition-opacity cursor-pointer shadow-md\">\n        <img src=\"https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?auto=format&fit=crop&q=80&w=600\" class=\"w-full object-cover rounded aspect-[3/4] hover:opacity-80 transition-opacity cursor-pointer shadow-md\">\n        <img src=\"https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=600\" class=\"w-full object-cover rounded aspect-[3/4] hover:opacity-80 transition-opacity cursor-pointer shadow-md\">\n      </div>\n    </div>\n\n    <!-- Biography info block -->\n    <div id=\"about\" class=\"max-w-2xl border-t border-neutral-800 pt-12 space-y-4\">\n      <h3 class=\"text-xs uppercase font-bold text-neutral-400 tracking-widest\">Biography</h3>\n      <p class=\"text-sm text-neutral-400 leading-relaxed\">Capturing raw human emotion, subtle movements, and geometric portraits inside studios and industrial layouts. Working with modern fashion, editorial, and design publications globally.</p>\n    </div>\n\n    <!-- Pricing / Rates -->\n    <div id=\"rates\" class=\"max-w-3xl border-t border-neutral-800 pt-12 space-y-6\">\n      <h3 class=\"text-xs uppercase font-bold text-neutral-400 tracking-widest\">Session Rates</h3>\n      <div class=\"grid grid-cols-1 sm:grid-cols-3 gap-4 text-xs font-bold uppercase tracking-wider\">\n        <div class=\"p-6 bg-neutral-900 border border-neutral-800 rounded\">\n          <h4>Half Day Studio</h4>\n          <p class=\"text-neutral-500 mt-1\">4 Hours &middot; $400</p>\n        </div>\n        <div class=\"p-6 bg-neutral-900 border border-neutral-800 rounded\">\n          <h4>Full Day Studio</h4>\n          <p class=\"text-neutral-500 mt-1\">8 Hours &middot; $750</p>\n        </div>\n        <div class=\"p-6 bg-neutral-900 border border-neutral-800 rounded\">\n          <h4>Commercial Shoot</h4>\n          <p class=\"text-neutral-500 mt-1\">Custom &middot; Rates Vary</p>\n        </div>\n      </div>\n    </div>\n\n    <!-- Booking Intake Form -->\n    <div id=\"contact\" class=\"max-w-2xl border-t border-neutral-800 pt-12 space-y-6\">\n      <h3 class=\"text-xs uppercase font-bold text-neutral-400 tracking-widest\">Book Session</h3>\n      <form data-studiopro-form data-form-name=\"Lens Studio Booking\" class=\"flex flex-col gap-3 max-w-md\">\n        <input name=\"email\" type=\"email\" class=\"w-full p-3.5 bg-neutral-900 text-white text-xs border border-neutral-800 rounded outline-none focus:border-white placeholder:text-neutral-600\" placeholder=\"creative@partner.com\" required />\n        <button class=\"bg-white hover:bg-neutral-200 text-black text-xs font-bold uppercase tracking-wider py-3 rounded\" type=\"submit\">Submit Request</button>\n      </form>\n    </div>\n  </main>\n</div>",
