    "html": "<div class=\"bg-[#0B0D17] text-white font-sans min-h-screen flex flex-col\">\n  <!-- Navbar -->\n  <header class=\"w-full border-b border-white/5 bg-[#0B0D17]/90 backdrop-blur sticky top-0 z-50 px-8 py-4 flex items-center justify-between\">\n    <div class=\"flex items-center gap-2\">\n      <span class=\"text-pink-500 text-lg font-black tracking-wider\">SARAH.</span>\n    </div>\n    <nav class=\"hidden md:flex gap-6 text-xs font-bold uppercase tracking-widest text-gray-400\">\n      <a href=\"#vlog\" class=\"hover:text-white transition-colors\">Videos</a>\n      <a href=\"#art\" class=\"hover:text-white transition-colors\">Portfolio</a>\n      <a href=\"#about\" class=\"hover:text-white transition-colors\">About</a>\n      <a href=\"#contact\" class=\"hover:text-white transition-colors\">Collabs</a>\n    </nav>\n    <a href=\"#contact\" class=\"bg-gradient-to-r from-pink-500 to-purple-500 text-white px-4 py-2 rounded-xl text-xs font-bold uppercase tracking-wider hover:brightness-110 active:scale-95 transition-all\">Get in Touch</a>\n  </header>\n\n  <!-- Hero Section -->\n  <section class=\"py-24 px-8 text-center max-w-4xl mx-auto flex flex-col items-center gap-6\">\n    <div class=\"relative\">\n      <div class=\"absolute inset-0 bg-gradient-to-tr from-pink-500 to-purple-500 rounded-full blur-md opacity-60\"></div>\n      <img src=\"https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?auto=format&fit=crop&q=80&w=200\" class=\"relative w-24 h-24 rounded-full object-cover border-4 border-[#0B0D17] shadow-xl\">\n    </div>\n    <div class=\"space-y-3\">\n      <h1 class=\"text-4xl md:text-5xl font-black tracking-tight leading-tight\">Sarah Creator</h1>\n      <p class=\"text-gray-400 text-sm uppercase tracking-widest font-bold\">Visual Artist & Video Producer ✨</p>\n    </div>\n    <p class=\"text-gray-400 text-base leading-relaxed max-w-xl\">Creating rich aesthetic edits, cinematic storytelling formats, and dynamic post-production assets for global brands and creative agencies.</p>\n    <div class=\"flex gap-4\">\n      <a href=\"#vlog\" class=\"bg-white text-black px-6 py-3 rounded-full font-bold hover:bg-gray-200 transition-all text-xs uppercase tracking-wider\">Latest Releases</a>\n      <a href=\"#contact\" class=\"bg-white/5 border border-white/10 text-white px-6 py-3 rounded-full font-bold hover:bg-white/10 transition-all text-xs uppercase tracking-wider\">Book Consultation</a>\n    </div>\n  </section>\n\n  <!-- Video Releases / Vlog Grid -->\n  <section id=\"vlog\" class=\"py-20 px-8 bg-[#131522] border-y border-white/5\">\n    <div class=\"max-w-5xl mx-auto space-y-12\">\n      <div class=\"flex justify-between items-end border-b border-white/10 pb-6\">\n        <h2 class=\"text-xl font-bold uppercase tracking-wider\">VIDEO PRODUCTION</h2>\n        <span class=\"text-xs text-gray-500 font-bold uppercase\">Recent Uploads</span>\n      </div>\n      <div class=\"grid grid-cols-1 md:grid-cols-2 gap-8\">\n        <div class=\"group space-y-4\">\n          <div class=\"aspect-video bg-black rounded-2xl overflow-hidden relative border border-white/5\">\n            <img src=\"https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?auto=format&fit=crop&q=80&w=600\" class=\"w-full h-full object-cover group-hover:scale-105 transition-transform duration-500\">\n            <div class=\"absolute inset-0 bg-black/40 flex items-center justify-center\">\n              <span class=\"material-symbols-outlined text-4xl text-white opacity-85 group-hover:scale-110 transition-transform\">play_circle</span>\n            </div>\n          </div>\n          <h3 class=\"font-bold text-sm\">Cinematic Portraits in Industrial Studios</h3>\n          <p class=\"text-xs text-gray-500\">Behind the scenes lighting breakdown &middot; 45K views</p>\n        </div>\n        <div class=\"group space-y-4\">\n          <div class=\"aspect-video bg-black rounded-2xl overflow-hidden relative border border-white/5\">\n            <img src=\"https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=600\" class=\"w-full h-full object-cover group-hover:scale-105 transition-transform duration-500\">\n            <div class=\"absolute inset-0 bg-black/40 flex items-center justify-center\">\n              <span class=\"material-symbols-outlined text-4xl text-white opacity-85 group-hover:scale-110 transition-transform\">play_circle</span>\n            </div>\n          </div>\n          <h3 class=\"font-bold text-sm\">Visual Identity: Dynamic Color Grading</h3>\n          <p class=\"text-xs text-gray-500\">Teardown of procedural art and styling editors &middot; 32K views</p>\n        </div>\n      </div>\n    </div>\n  </section>\n\n  <!-- Digital Art Portfolio Grid -->\n  <section id=\"art\" class=\"py-20 px-8 max-w-5xl mx-auto space-y-12\">\n    <div class=\"flex justify-between items-end border-b border-white/5 pb-6\">\n      <h2 class=\"text-xl font-bold uppercase tracking-wider\">DIGITAL ARTWORK</h2>\n      <span class=\"text-xs text-gray-500 font-bold uppercase\">Creative Index</span>\n    </div>\n    <div class=\"grid grid-cols-1 sm:grid-cols-3 gap-6\">\n      <div class=\"aspect-square bg-[#131522] rounded-2xl overflow-hidden border border-white/5\">\n        <img src=\"https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?auto=format&fit=crop&q=80&w=500\" class=\"w-full h-full object-cover hover:scale-105 transition-transform duration-500\">\n      </div>\n      <div class=\"aspect-square bg-[#131522] rounded-2xl overflow-hidden border border-white/5\">\n        <img src=\"https://images.unsplash.com/photo-1534528741775-53994a69daeb?auto=format&fit=crop&q=80&w=500\" class=\"w-full h-full object-cover hover:scale-105 transition-transform duration-500\">\n      </div>\n      <div class=\"aspect-square bg-[#131522] rounded-2xl overflow-hidden border border-white/5\">\n        <img src=\"https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?auto=format&fit=crop&q=80&w=500\" class=\"w-full h-full object-cover hover:scale-105 transition-transform duration-500\">\n      </div>\n    </div>\n  </section>\n\n  <!-- Business Inquiries Contact Form -->\n  <section id=\"contact\" class=\"py-20 px-8 bg-[#131522] border-t border-white/5\">\n    <div class=\"max-w-md mx-auto space-y-6\">\n      <div class=\"text-center space-y-2\">\n        <h3 class=\"text-2xl font-bold uppercase tracking-wider\">Start a Collaboration</h3>\n        <p class=\"text-xs text-gray-500\">Submit project specifications for business bookings.</p>\n      </div>\n      <form data-studiopro-form data-form-name=\"Creator Intake Form\" class=\"flex flex-col gap-4 font-sans text-xs\">\n        <div>\n          <label class=\"text-[9px] uppercase tracking-widest font-bold text-gray-500\">Brand Email</label>\n          <input name=\"email\" type=\"email\" class=\"w-full mt-1.5 p-3.5 bg-[#0B0D17] border border-white/10 rounded-xl text-white outline-none focus:border-pink-500 placeholder:text-gray-700\" placeholder=\"brand@company.com\" required />\n        </div>\n        <button class=\"w-full bg-gradient-to-r from-pink-500 to-purple-500 text-white font-bold py-3.5 rounded-xl uppercase tracking-wider hover:brightness-110 active:scale-95 transition-all\" type=\"submit\">Submit Request</button>\n      </form>\n    </div>\n  </section>\n\n  <!-- Footer -->\n  <footer class=\"w-full bg-[#0B0D17] text-gray-500 py-8 px-8 text-center text-xs font-bold border-t border-white/5 uppercase tracking-widest\">\n    <div class=\"max-w-5xl mx-auto flex justify-between items-center\">\n      <span>SARAH CREATOR &copy; 2026</span>\n      <span>Aesthetic Publishing & Video</span>\n    </div>\n  </footer>\n</div>",
