    "html": "<div class=\"bg-orange-50 text-stone-800 font-serif min-h-screen flex flex-col\">\n  <!-- Header -->\n  <header class=\"w-full bg-orange-50 border-b border-orange-100 px-8 py-6 flex items-center justify-between sticky top-0 z-50\">\n    <div class=\"font-extrabold text-xl tracking-wider text-orange-950\">FOODIE.</div>\n    <nav class=\"hidden md:flex gap-8 text-xs font-sans uppercase font-bold tracking-widest text-stone-500\">\n      <a href=\"#recipe\" class=\"text-orange-950\">Recipe</a>\n      <a href=\"#ingredients\" class=\"hover:text-black\">Ingredients</a>\n      <a href=\"#steps\" class=\"hover:text-black\">Preparation</a>\n      <a href=\"#newsletter\" class=\"hover:text-black\">Subscribe</a>\n    </nav>\n    <a href=\"#newsletter\" class=\"bg-orange-950 text-white px-4 py-2 rounded font-sans text-xs uppercase font-bold hover:bg-orange-900\">Join Club</a>\n  </header>\n\n  <!-- Recipe Title & Hero -->\n  <main id=\"recipe\" class=\"max-w-4xl mx-auto px-6 py-12 w-full space-y-8\">\n    <div class=\"text-center space-y-4\">\n      <span class=\"text-xs font-sans font-bold uppercase tracking-widest text-orange-700 bg-orange-100 px-3 py-1 rounded-full\">Artisanal Baking</span>\n      <h1 class=\"text-4xl md:text-5xl font-bold text-orange-950\">Rustic Sourdough Boule</h1>\n      <p class=\"text-stone-500 text-sm font-sans max-w-xl mx-auto\">Master the art of natural wild-yeast sourdough fermentation inside dynamic home kitchen setups.</p>\n    </div>\n\n    <div class=\"aspect-[16/9] w-full rounded-2xl overflow-hidden shadow-lg bg-stone-100\">\n      <img src=\"https://images.unsplash.com/photo-1476224203421-9ac39bcb3327?auto=format&fit=crop&q=80&w=1200\" class=\"w-full h-full object-cover\">\n    </div>\n\n    <!-- Recipe Stats -->\n    <div class=\"grid grid-cols-3 gap-4 border-y border-orange-200 py-6 text-center font-sans text-xs uppercase\">\n      <div>\n        <div class=\"text-gray-400\">Prep Duration</div>\n        <div class=\"font-bold text-orange-950 text-base mt-1\">24 Hours</div>\n      </div>\n      <div>\n        <div class=\"text-gray-400\">Baking Time</div>\n        <div class=\"font-bold text-orange-950 text-base mt-1\">45 Mins</div>\n      </div>\n      <div>\n        <div class=\"text-gray-400\">Difficulty</div>\n        <div class=\"font-bold text-orange-950 text-base mt-1\">Advanced</div>\n      </div>\n    </div>\n\n    <!-- Ingredients Checklist -->\n    <div id=\"ingredients\" class=\"space-y-6 pt-6\">\n      <h3 class=\"text-xl font-bold text-orange-950\">Required Ingredients</h3>\n      <ul class=\"grid grid-cols-1 sm:grid-cols-2 gap-4 font-sans text-sm\">\n        <li class=\"p-4 bg-orange-100/50 rounded-xl flex items-center gap-3\">\n          <span class=\"w-3.5 h-3.5 rounded bg-orange-600 flex items-center justify-center text-white text-[10px]\">&#10003;</span>\n          <span>500g High-Protein Bread Flour</span>\n        </li>\n        <li class=\"p-4 bg-orange-100/50 rounded-xl flex items-center gap-3\">\n          <span class=\"w-3.5 h-3.5 rounded bg-orange-600 flex items-center justify-center text-white text-[10px]\">&#10003;</span>\n          <span>375g Lukewarm Water (75% Hydration)</span>\n        </li>\n        <li class=\"p-4 bg-orange-100/50 rounded-xl flex items-center gap-3\">\n          <span class=\"w-3.5 h-3.5 rounded bg-orange-600 flex items-center justify-center text-white text-[10px]\">&#10003;</span>\n          <span>100g Active Sourdough Starter</span>\n        </li>\n        <li class=\"p-4 bg-orange-100/50 rounded-xl flex items-center gap-3\">\n          <span class=\"w-3.5 h-3.5 rounded bg-orange-600 flex items-center justify-center text-white text-[10px]\">&#10003;</span>\n          <span>10g Fine Sea Salt</span>\n        </li>\n      </ul>\n    </div>\n\n    <!-- Preparation steps -->\n    <div id=\"steps\" class=\"space-y-8 pt-8 border-t border-orange-200\">\n      <h3 class=\"text-xl font-bold text-orange-950\">Preparation Walkthrough</h3>\n      <div class=\"space-y-6\">\n        <div class=\"flex gap-4\">\n          <div class=\"w-8 h-8 rounded-full bg-orange-950 text-white font-sans text-xs font-bold flex items-center justify-center shrink-0\">1</div>\n          <div class=\"space-y-2\">\n            <h4 class=\"font-bold text-orange-950\">Autolyse Matrix</h4>\n            <p class=\"text-stone-600 text-sm leading-relaxed\">Combine bread flour and water in a large ceramic bowl. Cover and let stand for 1 hour to trigger natural gluten activation.</p>\n          </div>\n        </div>\n        <div class=\"flex gap-4\">\n          <div class=\"w-8 h-8 rounded-full bg-orange-950 text-white font-sans text-xs font-bold flex items-center justify-center shrink-0\">2</div>\n          <div class=\"space-y-2\">\n            <h4 class=\"font-bold text-orange-950\">Stretch & Fold Telemetry</h4>\n            <p class=\"text-stone-600 text-sm leading-relaxed\">Add active sourdough starter and salt. Run 4 rounds of bulk stretch-and-folds spaced 30 minutes apart to reinforce build elasticity.</p>\n          </div>\n        </div>\n      </div>\n    </div>\n\n    <!-- Join Food List -->\n    <div id=\"newsletter\" class=\"max-w-md mx-auto text-center space-y-4 pt-12 border-t border-orange-200\">\n      <h3 class=\"text-xl font-bold text-orange-950\">Receive Culinary Digests</h3>\n      <p class=\"text-stone-500 text-xs font-sans\">Get seasonal baking guides, starter tips, and restaurant catalogs.</p>\n      <form data-studiopro-form data-form-name=\"Foodie Subscriber\" class=\"flex gap-2 font-sans text-xs\">\n        <input name=\"email\" type=\"email\" class=\"flex-1 px-4 py-3 bg-orange-100/50 border border-orange-200 text-orange-950 rounded-full outline-none focus:border-orange-950 placeholder:text-orange-900/50\" placeholder=\"chef@kitchen.com\" required />\n        <button class=\"bg-orange-950 hover:bg-orange-900 text-white font-bold px-6 rounded-full uppercase tracking-wider\" type=\"submit\">Join</button>\n      </form>\n    </div>\n  </main>\n\n  <!-- Footer -->\n  <footer class=\"w-full bg-orange-950 text-orange-100/50 py-8 text-center text-xs font-sans uppercase tracking-widest border-t border-orange-900 mt-auto\">\n    <span>FOODIE CHRONICLES &copy; 2026 &middot; Artisanal Recipes</span>\n  </footer>\n</div>",
